#include <thread>
#include <stop_token>
#include <iostream>

int main() {
    // Часть 1: jthread автоматически join-ится при уничтожении
    std::cout << "--- jthread auto-join ---\n";
    {
        std::jthread t([] {
            for (int i = 1; i <= 3; ++i)
                std::cout << "worker step " << i << "\n";
        });
        // деструктор: request_stop() + join() — автоматически
    }
    std::cout << "scope ended: jthread joined automatically\n\n";

    // Часть 2: stop_source / stop_token / stop_callback (однопоточно)
    std::cout << "--- stop_source / stop_token API ---\n";
    std::stop_source ss;
    std::stop_token st = ss.get_token();

    std::cout << "stop_requested before: " << st.stop_requested() << "\n";

    bool callback_fired = false;
    std::stop_callback cb(st, [&] {
        callback_fired = true;
        std::cout << "stop_callback fired\n";
    });

    ss.request_stop();  // запускает cb синхронно
    std::cout << "stop_requested after:  " << st.stop_requested() << "\n";
    std::cout << "callback_fired: " << callback_fired << "\n";
}

#include <thread>
#include <stop_token>
#include <iostream>
#include <mutex>
#include <condition_variable>

int main() {
    // jthread автоматически передаёт stop_token первым аргументом,
    // если функция потока его принимает
    std::cout << "--- jthread passes stop_token automatically ---\n";

    std::mutex mtx;
    std::condition_variable_any cv;
    bool data_ready = false;

    auto worker = [&](std::stop_token st) {
        std::unique_lock lock(mtx);
        // condition_variable_any::wait с stop_token:
        // просыпается когда predicate == true ИЛИ когда запрошена остановка
        cv.wait(lock, st, [&] { return data_ready; });
        if (st.stop_requested() && !data_ready)
            std::cout << "worker: cancelled\n";
        else
            std::cout << "worker: data_ready=" << data_ready << "\n";
    };

    // Сценарий: отменяем до того, как data_ready стал true
    {
        std::jthread t(worker);  // stop_token передаётся автоматически!
        t.request_stop();
        // деструктор делает join()
    }
    std::cout << "jthread done\n\n";

    // --- stop_callback: регистрация нескольких обработчиков ---
    std::cout << "--- stop_source + stop_callback ---\n";
    std::stop_source src;
    std::stop_token tok = src.get_token();

    std::stop_callback cb1(tok, [] { std::cout << "callback 1 fired\n"; });
    std::stop_callback cb2(tok, [] { std::cout << "callback 2 fired\n"; });

    std::cout << "requesting stop...\n";
    src.request_stop();  // cb1 и cb2 срабатывают синхронно здесь
    std::cout << "stop done, stop_requested=" << tok.stop_requested() << "\n";

    // Регистрация после остановки: срабатывает немедленно в конструкторе
    std::stop_callback cb3(tok, [] { std::cout << "callback 3 (late) fired\n"; });
    std::cout << "end\n";
}

#include <latch>
#include <iostream>
#include <thread>
#include <vector>
#include <string>

int main() {
    const int N = 3;
    std::latch ready(N);           // обратный отсчёт от N
    std::vector<std::string> results(N);

    std::vector<std::thread> threads;
    for (int i = 0; i < N; ++i) {
        threads.emplace_back([&, i] {
            results[i] = "result_" + std::to_string(i);
            ready.count_down();    // сигнал: я завершил
        });
    }

    ready.wait();                  // ждём, пока все N не завершат

    std::cout << "All workers done:\n";
    for (const auto& r : results)
        std::cout << "  " << r << "\n";

    for (auto& t : threads) t.join();

    // После обнуления latch навсегда открыт
    ready.wait();  // немедленный возврат
    std::cout << "wait() after zero: returns immediately\n";

    // arrive_and_wait: count_down + wait атомарно (N=1)
    std::cout << "\n--- single-phase sync ---\n";
    std::latch gate(1);
    gate.arrive_and_wait();
    std::cout << "passed gate\n";
}

#include <barrier>
#include <semaphore>
#include <iostream>
#include <thread>

int main() {
    // --- std::barrier: многоразовый барьер ---
    // Для детерминированного вывода используем N=1:
    // это чисто API-демонстрация без гонок вывода.
    std::cout << "--- std::barrier API demo (N=1) ---\n";
    {
        int phase = 0;
        auto on_done = [&] { ++phase; };
        std::barrier<decltype(on_done)> bar(1, on_done);

        bar.arrive_and_wait();  // фаза 0 -> 1
        std::cout << "after 1st phase, phase=" << phase << "\n";
        bar.arrive_and_wait();  // фаза 1 -> 2
        std::cout << "after 2nd phase, phase=" << phase << "\n";
        bar.arrive_and_wait();  // многоразовый!
        std::cout << "after 3rd phase, phase=" << phase << "\n";
    }

    // --- std::counting_semaphore ---
    std::cout << "\n--- std::counting_semaphore ---\n";
    {
        std::counting_semaphore<2> sem(2);  // макс. 2 разрешения

        sem.acquire();  // разрешений: 2 -> 1
        std::cout << "acquired #1\n";
        sem.acquire();  // разрешений: 1 -> 0
        std::cout << "acquired #2\n";
        // sem.acquire() здесь заблокировалась бы (0 разрешений)
        sem.release();  // разрешений: 0 -> 1
        std::cout << "released #1\n";
        sem.release();  // разрешений: 1 -> 2
        std::cout << "released #2\n";
    }

    // --- std::binary_semaphore: сигнал продьюсер -> консьюмер ---
    std::cout << "\n--- std::binary_semaphore ---\n";
    {
        std::binary_semaphore ready(0);  // начально: не сигнализирован
        std::string message;

        std::thread producer([&] {
            message = "hello from producer";
            ready.release();  // сигнализируем консьюмера
        });

        ready.acquire();  // ожидаем продьюсера
        std::cout << "consumer got: " << message << "\n";
        producer.join();
    }
}

#include <atomic>
#include <iostream>
#include <vector>
#include <thread>

int main() {
    // --- atomic_ref: атомарный доступ к обычной переменной ---
    std::cout << "--- std::atomic_ref ---\n";

    // Обычный вектор; потоки работают с разными индексами
    std::vector<int> counters(4, 0);

    std::vector<std::thread> threads;
    for (int t = 0; t < 8; ++t) {
        threads.emplace_back([&, t] {
            int bucket = t % 4;
            std::atomic_ref<int> ref(counters[bucket]);
            for (int i = 0; i < 1000; ++i)
                ref.fetch_add(1, std::memory_order_relaxed);
        });
    }
    for (auto& t : threads) t.join();

    int total = 0;
    for (int i = 0; i < 4; ++i) {
        std::cout << "counters[" << i << "] = " << counters[i] << "\n";
        total += counters[i];
    }
    std::cout << "total = " << total << " (expected 8000)\n";

    // --- atomic_flag::test() — новое в C++20 ---
    std::cout << "\n--- std::atomic_flag::test() ---\n";
    std::atomic_flag flag = ATOMIC_FLAG_INIT;
    std::cout << "initial test(): " << flag.test() << "\n";       // 0
    flag.test_and_set();
    std::cout << "after test_and_set(): " << flag.test() << "\n"; // 1
    flag.clear();
    std::cout << "after clear(): " << flag.test() << "\n";        // 0
}

#include <atomic>
#include <memory>
#include <iostream>
#include <thread>

struct Config {
    int version;
    std::string name;
};

int main() {
    // --- std::atomic<shared_ptr<Config>> ---
    std::cout << "--- std::atomic<shared_ptr<Config>> ---\n";

    std::atomic<std::shared_ptr<Config>> current{
        std::make_shared<Config>(Config{1, "initial"})
    };

    // Атомарная загрузка — безопасна из любого потока
    auto snap = current.load();
    std::cout << "loaded v" << snap->version << ": " << snap->name << "\n";

    // Атомарная замена
    auto next = std::make_shared<Config>(Config{2, "updated"});
    current.store(std::move(next));
    snap = current.load();
    std::cout << "after store: v" << snap->version << ": " << snap->name << "\n";

    // compare_exchange: CAS на shared_ptr
    auto expected = snap;
    auto replacement = std::make_shared<Config>(Config{3, "final"});
    bool swapped = current.compare_exchange_strong(expected, replacement);
    std::cout << "compare_exchange_strong swapped=" << swapped << "\n";
    std::cout << "current: v" << current.load()->version << "\n\n";

    // --- Atomic wait / notify_one ---
    std::cout << "--- atomic<int> wait / notify_one ---\n";
    {
        std::atomic<int> flag{0};
        std::thread producer([&] {
            flag.store(1, std::memory_order_release);
            flag.notify_one();  // будим потребителя
        });
        flag.wait(0, std::memory_order_acquire);  // блокируемся, пока flag == 0
        std::cout << "consumer woke, flag = " << flag.load() << "\n";
        producer.join();
    }

    // --- notify_all и wait, когда значение уже отличается ---
    std::cout << "\n--- atomic<int> wait / notify_all (API demo) ---\n";
    {
        std::atomic<int> val{0};
        val.store(42);
        val.notify_all();  // широковещательное пробуждение; нет ждущих — no-op
        std::cout << "notify_all called, val = " << val.load() << "\n";
        // wait не блокируется, если текущее значение != ожидаемого
        val.wait(0);  // val == 42, не 0 — мгновенный возврат
        std::cout << "wait(0) returned immediately (val != 0)\n";
    }

    std::cout << "done\n";
}
